changeSet.sql:
ALTER TABLE saga_step_result ADD COLUMN IF NOT EXISTS step_started_at timestamptz;
CREATE TABLE IF NOT EXISTS saga_step_call ( id bigserial NOT NULL, saga_id uuid NOT NULL, step_name text NOT NULL, phase text NOT NULL, attempt integer NOT NULL DEFAULT 0, request_url text, request_body jsonb, status_code integer, response_body jsonb, error text, step_started_at timestamptz NOT NULL, created_at timestamptz NOT NULL, started_at timestamptz NOT NULL, PRIMARY KEY (id, started_at) ) PARTITION BY RANGE (started_at);
CREATE INDEX IF NOT EXISTS idx_saga_step_call_saga_id_started_at ON saga_step_call (saga_id, started_at);
